const jwtService = require("./jwtService")

const messageEmail = (data, url) => {
    return `
    <h1>Hola ${data.nombre}, un placer conocerte.</h1>
    <p>Gracias por registrarte en MerchNova. Para activar tu cuenta, haz clic en el siguiente enlace:</p>
    <a href="${url}">Activar mi cuenta</a>
    <p>Si no te has registrado en nuestro sitio web, puedes ignorar este correo electrónico.</p>
    <p>Saludos,</p>
    <p>Asistencia de MerchNova</p>
    <hr>
    <img src="cid:id-logoMN" alt="Logo de MerchNova" width="300">
`
}

const messageSetPassword = (data, url) => {
    return `
    <h1>Hola ${data.nombre},</h1>
    <p>Este email ha sido enviado para poder restablecer tu contraseña: </p>
    <a href="${url}">Restablecer contraseña</a>
    <p>Si no has sido tu quien ha provocado esta acción, puedes ignorar este correo electrónico.</p>
    <p>Saludos,</p>
    <p>Asistencia de MerchNova</p>
    <hr>
    <img src="cid:id-logoMN" alt="Logo de MerchNova" width="300">`
}

module.exports = {
    sendEmail: async (clientData, token) => {
        try {
            const EnlaceActivacion = `http://localhost:3000/api/Cliente/ActivacionCuenta?token=${token}&email=${clientData.email}`;
            const BASE64_APIKEYS_COD = Buffer.from(`${process.env.MAILJET_PUBLIC_KEY}:${process.env.MAILJET_SECRET_KEY}`).toString('base64');

            const MailjetBody = JSON.stringify({
                "Messages": [
                    {
                        "From": {
                            "Email": `eduardosuarezalvarado3@gmail.com`,
                            "Name": "Asistente de MerchNova"
                        },
                        "To": [
                            {
                                "Email": clientData.email,
                                "Name": clientData.nombre
                            }
                        ],
                        "Subject": "Activación de tu cuenta de MerchNova",
                        "HTMLPart": messageEmail(clientData, EnlaceActivacion),
                        "InlinedAttachments": [
                            {
                                "ContentType": "image/png",
                                "Filename": "logoMerchNova.png",
                                "ContentID": "id-logoMN",
                                "Base64Content": ""
                            }
                        ]
                    }
                ]
            })

            const peticionSendMailjet = await fetch('https://api.mailjet.com/v3.1/send', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Basic ${BASE64_APIKEYS_COD}`
                },
                body: MailjetBody
            })

            const bodyResponseMailjet = await peticionSendMailjet.json();

            console.log('Respuesta de Mailjet:', bodyResponseMailjet);
            if (bodyResponseMailjet.Messages[0].Status !== 'success') throw new Error('No se pudo enviar el email de activación');
            return bodyResponseMailjet;
        } catch (error) {

        }
    },

    sendEmailForSetPassword: async (clientData, email) => {
        try {
            const token = jwtService.generateToken({idCliente: clientData._id, email: email}, {expiresIn: '10min'});
            const EnlaceComponent = `${process.env.URL_FRONTEND}Cliente/CambiarClave?clientId=${clientData._id}&tokenPasswd=${token}`;
            const BASE64_APIKEYS_COD = Buffer.from(`${process.env.MAILJET_PUBLIC_KEY}:${process.env.MAILJET_SECRET_KEY}`).toString('base64');

            const MailjetBody = JSON.stringify({
                "Messages": [
                    {
                        "From": {
                            "Email": `eduardosuarezalvarado3@gmail.com`,
                            "Name": "Asistente de MerchNova"
                        },
                        "To": [
                            {
                                "Email": email,
                                "Name": clientData.nombre
                            }
                        ],
                        "Subject": "Restablecer tu contraseña de MerchNova",
                        "HTMLPart": messageSetPassword(clientData, EnlaceComponent),
                        "InlinedAttachments": [
                            {
                                "ContentType": "image/png",
                                "Filename": "logoMerchNova.png",
                                "ContentID": "id-logoMN",
                                "Base64Content": ""
                            }
                        ]
                    }
                ]
            })

            const peticionSendMailjet = await fetch('https://api.mailjet.com/v3.1/send', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Basic ${BASE64_APIKEYS_COD}`
                },
                body: MailjetBody
            })

            const bodyResponseMailjet = await peticionSendMailjet.json();

            console.log('Respuesta de Mailjet:', bodyResponseMailjet);
            if (bodyResponseMailjet.Messages[0].Status !== 'success') throw new Error('No se pudo enviar el email de activación');
            return bodyResponseMailjet;
        } catch (error) {
            console.log('Error al enviar email: ', error.message)
        }
    }
}